// Parse filter parameters from master workflow input
const input = $input.first().json;

const filterByType = input.filter_by_type || null;
const filterByIds = input.filter_by_ids ? JSON.parse(input.filter_by_ids) : null;
const hostname = input.hostname || input.wer || null;

return [{
  json: {
    filter_by_type: filterByType,
    filter_by_ids: filterByIds,
    hostname: hostname,
    netbox_token: '6e517f4e4fd4b3f3d3de63770bd79e6faacf0fe4',
    netbox_base: 'http://10.1.1.104'
  }
}];

// Merge and normalize all NetBox results into unified format
const allItems = $input.all();

// allItems[0] = VMs, allItems[1] = LXCs, allItems[2] = Devices
// Note: In splitInBatches context we get all results merged

function extractIP(primaryIp) {
  if (!primaryIp || !primaryIp.address) return null;
  return primaryIp.address.split('/')[0];
}

function normalizeVM(vm, typeOverride) {
  const cfVmType = vm.custom_fields && vm.custom_fields.vm_type;
  const type = typeOverride || (cfVmType === 'lxc' ? 'lxc' : 'vm');
  return {
    id: vm.id,
    name: vm.name,
    ip: extractIP(vm.primary_ip4 || vm.primary_ip),
    type: type,
    ssh_user: (vm.custom_fields && vm.custom_fields.ssh_user) || 'root',
    ssh_password: (vm.custom_fields && vm.custom_fields.ssh_password) || '',
    cluster: vm.cluster ? vm.cluster.name : null,
    status: vm.status ? vm.status.value : 'unknown'
  };
}

function normalizeDevice(dev) {
  return {
    id: dev.id,
    name: dev.name,
    ip: extractIP(dev.primary_ip4 || dev.primary_ip),
    type: 'device',
    ssh_user: (dev.custom_fields && dev.custom_fields.ssh_user) || 'root',
    ssh_password: (dev.custom_fields && dev.custom_fields.ssh_password) || '',
    cluster: dev.site ? dev.site.name : null,
    status: dev.status ? dev.status.value : 'unknown'
  };
}

const normalized = [];

for (const item of allItems) {
  const data = item.json;
  if (data && data.results) {
    for (const entry of data.results) {
      // Detect if device (has device_type) or VM
      if (entry.device_type !== undefined) {
        normalized.push(normalizeDevice(entry));
      } else {
        normalized.push(normalizeVM(entry, null));
      }
    }
  }
}

// Deduplicate by id+type
const seen = new Set();
const deduped = normalized.filter(item => {
  const key = `${item.type}_${item.id}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return [{ json: { systems: deduped, total: deduped.length } }];

// Apply filters to the normalized system list
const data = $input.first().json;
const systems = data.systems || [];

// Get filter params from earlier in the workflow
const filterNode = $('🔧 Parse Filter Parameters').first().json;
const filterByType = filterNode.filter_by_type;
const filterByIds = filterNode.filter_by_ids;
const hostname = filterNode.hostname;

let filtered = [...systems];

// Filter by type (vm, lxc, device)
if (filterByType && filterByType !== '') {
  filtered = filtered.filter(s => s.type === filterByType);
}

// Filter by specific IDs
if (filterByIds && Array.isArray(filterByIds) && filterByIds.length > 0) {
  const idSet = new Set(filterByIds.map(String));
  filtered = filtered.filter(s => idSet.has(String(s.id)));
}

// Filter by hostname (partial match)
if (hostname && hostname !== '') {
  const hn = hostname.toLowerCase();
  filtered = filtered.filter(s => s.name && s.name.toLowerCase().includes(hn));
}

// Filter out systems without IP (can't SSH)
const withIp = filtered.filter(s => s.ip);
const withoutIp = filtered.filter(s => !s.ip);

// Return each system as individual item for loop processing
const output = withIp.map(system => ({ json: system }));

if (output.length === 0) {
  return [{ json: { id: null, name: 'NO_SYSTEMS_FOUND', ip: null, type: null, ssh_user: null, ssh_password: null, cluster: null, _empty: true } }];
}

return output;
